const now = new Date();
const runSeed = `${now.getTime()}-${Math.random().toString(36).slice(2, 8)}`;
const sessionId = `rosalynn-${runSeed}`;
const notionDatabaseId = process.env.NOTION_EVENT_DB_ID || '';
const statusProperty = process.env.NOTION_STATUS_PROPERTY || 'Workflow Status';
const readyValue = process.env.NOTION_READY_STATUS || 'Ready to Generate';
const pageSize = Number(process.env.NOTION_READY_PAGE_SIZE || 100);

return [{
  json: {
    runStartedAt: now.toISOString(),
    sessionId,
    fetchReadyEventsPayload: {
      session_id: sessionId,
      sync_response_to_workbench: false,
      current_step: 'FETCH_READY_EVENTS',
      tools: [
        {
          tool_slug: 'NOTION_QUERY_DATABASE_WITH_FILTER',
          arguments: {
            database_id: notionDatabaseId,
            page_size: pageSize,
            filter: {
              property: statusProperty,
              select: { equals: readyValue }
            },
            sorts: [
              { timestamp: 'last_edited_time', direction: 'ascending' }
            ]
          }
        }
      ]
    }
  }
}];

const raw = $json;

const tryArray = (value) => (Array.isArray(value) ? value : []);

const candidates = [
  raw?.data?.results,
  raw?.data?.toolsOutput?.[0]?.data?.results,
  raw?.data?.tools_output?.[0]?.data?.results,
  raw?.data?.tool_results?.[0]?.data?.results,
  raw?.data?.response?.[0]?.data?.results,
  raw?.results
];

const rows = candidates.find((value) => Array.isArray(value)) || [];

const getRichText = (arr) => Array.isArray(arr)
  ? arr.map((item) => item?.plain_text || '').join('').trim()
  : '';

const getSelect = (value) => value?.name || '';

const normalized = rows.map((row) => {
  const props = row?.properties || {};
  const eventId = getRichText(props['Event ID']?.rich_text) || row?.id || '';
  const versionRaw = props['Version']?.number;
  const version = Number.isFinite(versionRaw) ? versionRaw : 1;

  return {
    eventId,
    rowId: row?.id || '',
    version,
    actorRole: getSelect(props['Actor Role']?.select) || 'system',
    eventName: getRichText(props['Event Name']?.title) || getRichText(props['Event Name']?.rich_text),
    clientName: getRichText(props['Client Name']?.rich_text),
    eventDate: props['Event Date']?.date?.start || '',
    kitchenEmail: props['Kitchen Email']?.email || '',
    serviceEmail: props['Service Email']?.email || '',
    clientEmail: props['Client Email']?.email || '',
    payload: row
  };
});

return normalized.map((event) => ({ json: event }));

const now = new Date();
const timestamp = now.toISOString().replace(/[-:TZ]/g, '').slice(0, 14);
const runId = `run-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
const version = Number($json.version || 1);
const eventId = $json.eventId || `evt-${Date.now()}`;

const renderJobs = [
  {
    audience: 'kitchen',
    templateId: process.env.CARBONE_TEMPLATE_KITCHEN_ID || '',
    filename: `${eventId}_v${String(version).padStart(2, '0')}_kitchen_${timestamp}.pdf`
  },
  {
    audience: 'service',
    templateId: process.env.CARBONE_TEMPLATE_SERVICE_ID || '',
    filename: `${eventId}_v${String(version).padStart(2, '0')}_service_${timestamp}.pdf`
  },
  {
    audience: 'client',
    templateId: process.env.CARBONE_TEMPLATE_CLIENT_ID || '',
    filename: `${eventId}_v${String(version).padStart(2, '0')}_client_${timestamp}.pdf`
  }
];

const recipients = {
  kitchen: $json.kitchenEmail,
  service: $json.serviceEmail,
  client: $json.clientEmail
};

return [{
  json: {
    ...$json,
    eventId,
    version,
    runId,
    renderJobs,
    recipients
  }
}];

const baseCarboneUrl = process.env.CARBONE_API_BASE_URL || 'https://api.carbone.io';
const plan = $items('Build Render Plan', 0, 0)[0]?.json || $json;
const initContext = $items('Init Run Context', 0, 0)[0]?.json || {};

const kitchenRender = $items('Render Kitchen PDF', 0, 0)[0]?.json?.data?.renderId || '';
const serviceRender = $items('Render Service PDF', 0, 0)[0]?.json?.data?.renderId || '';
const clientRender = $items('Render Client PDF', 0, 0)[0]?.json?.data?.renderId || '';

const jobByAudience = Object.fromEntries((plan.renderJobs || []).map((job) => [job.audience, job]));

const toDoc = (audience, renderId) => ({
  audience,
  recipientEmail: plan.recipients?.[audience] || '',
  documentUrl: `${baseCarboneUrl}/render/${renderId}?download=true`,
  documentAudience: audience,
  documentVersion: plan.version,
  filename: jobByAudience[audience]?.filename || `${plan.eventId}_${audience}.pdf`
});

const dispatches = [
  toDoc('kitchen', kitchenRender),
  toDoc('service', serviceRender),
  toDoc('client', clientRender)
].filter((entry) => entry.recipientEmail && entry.documentUrl.includes('/render/'));

const buildAudienceBody = (entry) => [
  `Event ${plan.eventId} is ready (v${plan.version}).`,
  `Audience: ${entry.audience}.`,
  '',
  `Document: ${entry.documentUrl}`,
  '',
  'This link is generated from Carbone and should be consumed promptly.'
].join('\\n');

const sendEmailPayload = {
  session_id: process.env.COMPOSIO_EMAIL_SESSION_ID || initContext.sessionId || '',
  sync_response_to_workbench: false,
  current_step: 'SEND_AUDIENCE_EMAILS',
  tools: dispatches.map((entry) => ({
    tool_slug: 'GMAIL_SEND_EMAIL',
    arguments: {
      recipient_email: entry.recipientEmail,
      subject: `[BEO ${plan.eventId}] ${entry.audience} packet v${plan.version}`,
      body: buildAudienceBody(entry),
      is_html: false
    }
  }))
};

return [{
  json: {
    ...plan,
    dispatches,
    sendEmailPayload
  }
}];
